let currentPage = 'dashboard';

function showPage(id) {
  // Cek permission sebelum buka halaman (kecuali dashboard)
  if (id !== 'dashboard' && !isAdmin() && typeof hasPerm === 'function') {
    if (!hasPerm(id, 'read')) {
      showAlert('⛔ Akses ditolak.\n\nKamu tidak punya izin untuk membuka modul ini.\nHubungi admin untuk mengatur ulang hak akses.');
      return;
    }
  }
  document.querySelectorAll('.page').forEach(p => {
    p.classList.remove('active');
    p.style.display = 'none';
  });
  // Handle both old nav-item and new nav-card
  document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('active'));
  document.querySelectorAll('.nav-card').forEach(n => n.classList.remove('active'));
  const _activePage = document.getElementById('page-'+id);
  if (_activePage) {
    _activePage.classList.add('active');
    _activePage.style.display = (id === 'audit-trail') ? 'flex' : 'block';
  }
  // Set active nav-item (legacy)
  document.querySelectorAll('.nav-item').forEach(n => {
    const oc = n.getAttribute('onclick') || '';
    if(oc === `showPage('${id}')`) n.classList.add('active');
  });
  // Set active nav-card by data-page attribute
  document.querySelectorAll('.nav-card[data-page]').forEach(n => {
    if(n.dataset.page === id) n.classList.add('active');
  });
  // History tracking (inline — no wrapper to avoid recursion)
  if(typeof isNavigating !== 'undefined' && !isNavigating && typeof pageHistory !== 'undefined') {
    safeHistoryPush({ page: id }, '', '#' + id);
    if(pageHistory[pageHistory.length - 1] !== id) pageHistory.push(id);
  }
  const t = pageTitles[id] || [id, ''];
  document.getElementById('page-title').textContent = t[0];
  document.getElementById('page-sub').textContent = t[1];
  currentPage = id;
  // Render
  if(id==='dashboard') { renderDashboard(); setTimeout(upgradeFormPickers, 150); }
  if(id==='ai-assistant') { updateAIKeyStatus(); initChipsState(); }
  // Setup number inputs for calculator pages
  if(id && id.startsWith('kalk')) setTimeout(() => { setupNumberInputs(); upgradeFormPickers(); upgradePajakPickers(); }, 300);
  if(id==='jurnal-umum') { renderJurnalUmum(); setTimeout(upgradeFormPickers, 80); }
  if(id==='rekonsiliasi-bank') { setTimeout(upgradeFormPickers, 80); }
  if(id==='jurnal-kas') { renderJurnalKas(); setTimeout(upgradeFormPickers, 80); }
  if(id==='jurnal-penjualan') { renderJurnalPenjualan(); setTimeout(upgradeFormPickers, 80); }
  if(id==='jurnal-pembelian') { renderJurnalPembelian(); setTimeout(upgradeFormPickers, 80); }
  if(id==='buku-besar') { renderBukuBesar(); setTimeout(upgradeFormPickers, 80); }
  if(id==='neraca-saldo') renderNeracaSaldo();
  if(id==='laba-rugi') { renderLabaRugi(); setTimeout(addPeriodFilterToReports,80); }
  if(id==='neraca-saldo') setTimeout(addPeriodFilterToReports,80);
  if(id==='neraca') renderNeraca();
  if(id==='arus-kas') { renderArusKas(); setTimeout(upgradeFormPickers, 80); }
  if(id==='perubahan-ekuitas') { renderPerubahanEkuitas(); setTimeout(upgradeFormPickers, 80); }
  if(id==='aset-tetap') setTimeout(()=>{ renderAsetTetap(); renderAsetTetapKPI(); upgradeFormPickers(); }, 80);
  if(id==='kontak') setTimeout(()=>{ renderKontak(); renderKontakKPI(); upgradeFormPickers(); }, 80);
  if(id==='kalk-persediaan') setTimeout(()=>{
    // Pastikan activeKartuStockId/activeKategoriId terisi dan data di-sync sebelum render
    if(!activeKartuStockId) {
      const firstCard = Object.values(multiKartuStock)[0];
      if(firstCard) {
        activeKartuStockId = firstCard.id;
        activeKategoriId = firstCard.kategori ? Object.keys(firstCard.kategori)[0] : null;
      }
    }
    if(!activeKategoriId && activeKartuStockId) {
      const card = multiKartuStock[activeKartuStockId];
      if(card?.kategori) activeKategoriId = Object.keys(card.kategori)[0];
    }
    syncKartuStockDataFromKategori();
    renderKartuStockSelector();
    renderKartuStock();
    upgradeFormPickers();
    // Fix sticky header setelah semua render selesai
    fixKsTableStickyHeaders();
  }, 80);
  if(id==='akun') { renderAkun(); setTimeout(upgradeFormPickers, 80); }
  if(id==='transaksi') { initTransaksiForm(); setTimeout(() => { upgradeFormPickers(); refreshKontakPickers(); }, 80); }
  if(id==='analitik') setTimeout(renderAnalitik, 80);
  // Fitur Baru
  if(id==='jurnal-berulang') setTimeout(()=>{ renderJurnalBerulang(); upgradeFormPickers(); }, 80);
  if(id==='invoice') setTimeout(()=>{ renderInvoiceList(); renderInvoiceKPI(); upgradeFormPickers(); }, 80);
  if(id==='rekonsiliasi') setTimeout(upgradeFormPickers, 80);
  if(id==='kurs') setTimeout(()=>{ renderKursPage(); upgradeFormPickers(); }, 80);
  if(id==='notifikasi') setTimeout(()=>{ renderNotifikasiPage(); upgradeFormPickers(); }, 80);
  if(id==='anggaran') setTimeout(()=>{ renderAnggaranPage(); upgradeFormPickers(); }, 80);
  if(id==='pajak') setTimeout(()=>{ renderPajakOtomatis(); }, 60);
}

function handleAddBtn() {
  showPage('transaksi');
}

// TABS
function switchTab(group, tab) {
  document.querySelectorAll('.trx-tab').forEach(t => t.style.display='none');
  document.getElementById(`${group}-${tab}`).style.display='block';
  document.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
  event.target.classList.add('active');
  if(tab==='umum') initManualLines();
  if(tab==='penjualan') initJualAkunPendapatan();
  if(tab==='simpel') {
    // tanggal tidak auto-fill — user wajib pilih sendiri
  }
}

// AKUN DROPDOWN
function populateAkunSelect(selId, filter=null) {
  // Jika elemen adalah hidden input (pakai picker), skip — nilai diset via picker
  const el = document.getElementById(selId);
  if(!el || el.type === 'hidden') return;
  el.innerHTML = '';
  akuns.filter(a => !filter || filter(a)).forEach(a => {
    const opt = document.createElement('option');
    opt.value = a.kode;
    opt.textContent = `${a.kode} - ${a.nama}`;
    el.appendChild(opt);
  });
}

// SIMPLE PICKER untuk form kas & pembelian
let _simplePickerHiddenId = null;
let _simplePickerBtnId = null;
let _simplePickerFilter = null;

const PICKER_FILTERS = {
  'kas':  a => !['1101','1102','1103','1104'].includes(a.kode),
  'beli': a => ['Beban','Aset','HPP'].includes(a.tipe),
};

function openSimplePicker(hiddenInputId, btnId, mode) {
  _simplePickerHiddenId = hiddenInputId;
  _simplePickerBtnId = btnId;
  _simplePickerFilter = PICKER_FILTERS[mode] || null;
  document.getElementById('akun-picker-search').value = '';
  const currentVal = document.getElementById(hiddenInputId)?.value || '';
  renderFilteredPickerList('', currentVal, _simplePickerFilter);
  document.getElementById('akun-picker-backdrop').classList.add('open');
  setTimeout(()=>document.getElementById('akun-picker-search').focus(), 200);
}

function renderFilteredPickerList(query, selectedKode, filterFn) {
  const q = query.toLowerCase();
  const base = filterFn ? akuns.filter(filterFn) : akuns;
  const filtered = base.filter(a =>
    !q || a.kode.includes(q) || a.nama.toLowerCase().includes(q) || a.tipe.toLowerCase().includes(q)
  );
  const list = document.getElementById('akun-picker-list');
  if(!filtered.length) {
    list.innerHTML = `<div id="akun-picker-empty"><i class="ti ti-mood-empty" style="font-size:20px;display:block;margin:0 auto 6px;"></i> Akun tidak ditemukan</div>`;
    return;
  }
  const groups = {};
  filtered.forEach(a => { if(!groups[a.tipe]) groups[a.tipe]=[]; groups[a.tipe].push(a); });
  const tipeColor = t => ({Aset:'aset',Liabilitas:'liabilitas',Ekuitas:'ekuitas',Pendapatan:'pendapatan',Beban:'beban',HPP:'beban'})[t]||'beban';
  let html = '';
  Object.entries(groups).forEach(([tipe,items]) => {
    html += `<div class="akun-picker-group-label">${tipe}</div>`;
    items.forEach(a => {
      const sel = a.kode===selectedKode ? ' selected' : '';
      html += `<div class="akun-picker-item${sel}" onclick="selectSimplePicker('${a.kode}','${a.nama.replace(/'/g,"\\'")}')">
        <span class="akun-picker-kode">${a.kode}</span>
        <span class="akun-picker-nama">${a.nama}</span>
        <span class="akun-picker-tipe ${tipeColor(a.tipe)}">${tipe}</span>
      </div>`;
    });
  });
  list.innerHTML = html;
}

function selectSimplePicker(kode, nama) {
  // Cek apakah ini simple picker (form) atau manual line picker
  if(_simplePickerHiddenId) {
    const hidden = document.getElementById(_simplePickerHiddenId);
    const btn = document.getElementById(_simplePickerBtnId);
    if(hidden) hidden.value = kode;
    if(btn) {
      btn.classList.add('has-value');
      // Buku besar picker has different inner HTML (opt-picker style)
      if(_simplePickerHiddenId === 'bb-akun-filter-val') {
        btn.innerHTML = `<span class="picker-kode-badge" style="font-family:var(--mono);font-size:11px;background:var(--surface2);border:1px solid var(--border);border-radius:4px;padding:2px 6px;margin-right:6px;">${kode}</span><span style="flex:1;overflow:hidden;text-overflow:ellipsis;">${nama}</span><span class="opt-picker-arrow">▾</span>`;
      } else {
        btn.classList.add('has-value');
        btn.innerHTML = `<span class="picker-kode-badge">${kode}</span><span style="flex:1;overflow:hidden;text-overflow:ellipsis;">${nama}</span>`;
      }
    }
    const isBukuBesar = _simplePickerHiddenId === 'bb-akun-filter-val';
    _simplePickerHiddenId = null;
    _simplePickerBtnId = null;
    _simplePickerFilter = null;
    document.getElementById('akun-picker-backdrop').classList.remove('open');
    // Trigger buku besar render after picker closes
    if(isBukuBesar) setTimeout(renderBukuBesar, 50);
  } else {
    // Delegate ke picker manual line
    selectAkunFromPicker(kode, nama);
    return;
  }
}

function initTransaksiForm() {
  // tanggal tidak auto-fill — user wajib pilih sendiri
  populateAkunSelect('kas-akun-lawan', a => !['1101','1102'].includes(a.kode));
  populateAkunSelect('beli-akun', a => ['Beban','Aset','HPP'].includes(a.tipe));

  // Pastikan beli-produk-row selalu visible (bisa tersembunyi jika akun non-persediaan dipilih sebelumnya)
  const produkRow = document.getElementById('beli-produk-row');
  if(produkRow) produkRow.style.display = '';

  // Pastikan akun default beli sudah menunjuk ke persediaan (1301) supaya produk picker tampil
  const beliAkunEl = document.getElementById('beli-akun');
  if(beliAkunEl && !['1301','1302','1303','1304'].includes(beliAkunEl.value)) {
    beliAkunEl.value = '1301';
    const beliAkunLbl = document.getElementById('beli-akun-label');
    if(beliAkunLbl) beliAkunLbl.textContent = 'Persediaan Barang Dagangan';
  }

  initManualLines();
}

// KAS
function previewKas() {
  const jenis = document.getElementById('kas-jenis').value;
  const akunKode = document.getElementById('kas-akun-lawan').value;
  const akunNama = akuns.find(a=>a.kode===akunKode)?.nama||'';
  const jumlah = parseFloat(document.getElementById('kas-jumlah').value)||0;
  const prev = document.getElementById('kas-preview');
  if(!jumlah) { prev.style.display='none'; return; }
  const lines = jenis==='masuk'
    ? [{akun:'Kas',d:jumlah,k:0},{akun:akunNama,d:0,k:jumlah}]
    : [{akun:akunNama,d:jumlah,k:0},{akun:'Kas',d:0,k:jumlah}];
  prev.style.display='block';
  prev.innerHTML = `<div style="background:var(--surface2);border:1px solid var(--border);border-radius:8px;padding:12px 14px;font-size:12.5px;">
    <div style="font-weight:600;margin-bottom:8px;color:var(--accent2);">Preview Jurnal</div>
    ${lines.map(l=>`<div style="display:flex;justify-content:space-between;padding:4px 0;font-family:var(--mono);">
      <span style="${l.d?'':'padding-left:24px'}">${l.akun}</span>
      <span style="color:var(--accent)">${l.d?fmtRp(l.d):''}</span>
      <span style="color:var(--red)">${l.k?fmtRp(l.k):''}</span>
    </div>`).join('')}
  </div>`;
}

function simpanKas() {
  const tanggal = document.getElementById('kas-tanggal').value;
  const jenis = document.getElementById('kas-jenis').value;
  const akunKode = document.getElementById('kas-akun-lawan').value;
  const jumlah = parseFloat(document.getElementById('kas-jumlah').value)||0;
  const ket = document.getElementById('kas-ket').value || (jenis==='masuk'?'Penerimaan Kas':'Pengeluaran Kas');
  if(!tanggal) { showAlert('Pilih tanggal terlebih dahulu!'); return; }
  if(!jumlah) { showAlert('Isi jumlah transaksi terlebih dahulu!'); return; }
  if(!akunKode) { showAlert('Pilih akun lawan terlebih dahulu!'); return; }
  const lines = jenis==='masuk'
    ? [{akun:'1101',ket:'Kas masuk',debit:jumlah,kredit:0},{akun:akunKode,ket,debit:0,kredit:jumlah}]
    : [{akun:akunKode,ket,debit:jumlah,kredit:0},{akun:'1101',ket:'Kas keluar',debit:0,kredit:jumlah}];
  addJurnal({tanggal,ket,jenis:'Kas',lines});
  document.getElementById('kas-jumlah').value='';
  document.getElementById('kas-ket').value='';
  document.getElementById('kas-preview').style.display='none';
  // Reset picker button
  const btn = document.getElementById('kas-akun-lawan-btn');
  if(btn){ btn.classList.remove('has-value'); btn.textContent = 'Pilih Akun...'; }
  document.getElementById('kas-akun-lawan').value = '';
  showAlert('✓ Jurnal Kas berhasil disimpan!');
}

// PENJUALAN
function getAkunPendapatanDefault() {
  // Auto-detect dari tipe bisnis currentCompany
  const tipe = currentCompany?.type || currentCompany?.tipe || '';
  if (tipe === 'jasa') return { kode: '4102', nama: 'Penjualan Jasa' };
  if (tipe === 'dagang') return { kode: '4101', nama: 'Penjualan Barang' };
  if (tipe === 'properti') return { kode: '4103', nama: 'Pendapatan Sewa' };
  if (tipe === 'manufaktur') return { kode: '4101', nama: 'Penjualan Barang' };
  return null; // umum = user pilih sendiri
}

