// NERACA
function renderNeraca() {
  let aset=0,liab=0,ekuitas=0;
  const asetRows=[],liabRows=[],ekRows=[];
  const labaBersih = (() => {
    let p=0,b=0;
    akuns.forEach(a=>{const s=getSaldoAkun(a.kode);if(a.tipe==='Pendapatan')p+=s;if(['Beban','HPP'].includes(a.tipe))b+=s;});
    return p-b;
  })();
  akuns.forEach(a=>{
    const s=getSaldoAkun(a.kode);
    if(!s&&a.tipe!=='Ekuitas') return;
    if(a.tipe==='Aset'){
      const v=a.normal==='D'?s:-s;
      aset+=v; asetRows.push([a.nama,v]);
    }
    if(a.tipe==='Liabilitas'){liab+=s;liabRows.push([a.nama,s]);}
    if(a.tipe==='Ekuitas'){
      // normal K (Modal, Laba Ditahan) → +ekuitas; normal D (Prive) → -ekuitas
      // Nilai s dari getSaldoAkun sudah positif (misal Prive = 500.000)
      // Di tabel: Prive tampil (500.000) sebagai pengurang, total ekuitas = modal + laba - prive
      if(a.normal==='D'){
        ekuitas -= s;       // dikurangi dari total ekuitas
        if(s) ekRows.push([a.nama, s, true]); // flag isPrive=true
      } else {
        if(s) ekuitas += s;
        ekRows.push([a.nama, s, false]);
      }
    }
  });
  // labaBersih ditambahkan ke ekuitas HANYA sekali — jangan double count
  const totalEkuitas = ekuitas + labaBersih;
  const secHtml=(title,rows,total,color)=>`
    <div class="table-card" style="margin-bottom:16px;">
      <div class="table-header"><div class="table-title">${title}</div></div>
      <table><tbody>
        ${rows.map(([n,v,isPrive])=>`<tr>
          <td style="padding-left:24px">${n}${isPrive?` <span style="font-size:10px;color:var(--muted);">(pengurang)</span>`:''}</td>
          <td class="num" style="text-align:right;color:${isPrive?'var(--red)':color};">${isPrive?'('+fmtRp(v)+')':fmtRp(v)}</td>
        </tr>`).join('')}
        ${title==='Ekuitas'?`<tr><td style="padding-left:24px">Laba Periode Berjalan</td><td class="num" style="text-align:right;color:var(--accent);">${fmtRp(labaBersih)}</td></tr>`:''}
      </tbody><tfoot><tr class="total-row"><td>Total ${title}</td><td class="num" style="text-align:right;">${fmtRp(total)}</td></tr></tfoot></table>
    </div>`;
  document.getElementById('neraca-content').innerHTML=`
    <div class="grid-2" style="align-items:start;">
      <div>${secHtml('Aset',asetRows,aset,'var(--accent)')}</div>
      <div>
        ${secHtml('Liabilitas',liabRows,liab,'var(--red)')}
        ${secHtml('Ekuitas',ekRows,totalEkuitas,'var(--accent2)')}
        <div class="table-card"><table><tbody>
          <tr class="total-row"><td>TOTAL LIAB + EKUITAS</td><td class="num" style="text-align:right;">${fmtRp(liab+totalEkuitas)}</td></tr>
        </tbody></table></div>
      </div>
    </div>
    <div style="font-size:12px;color:${Math.abs(aset-(liab+totalEkuitas))<1?'var(--accent)':'var(--red)'};margin-top:8px;font-family:var(--mono);">
      ${Math.abs(aset-(liab+totalEkuitas))<1?'✓ Neraca Balance':'✗ Neraca Tidak Balance — selisih: '+fmtRp(Math.abs(aset-(liab+totalEkuitas)))}
    </div>`;
}

// AKUN
function tipeBadge(t){
  if(t==='Aset') return 'badge-green';
  if(t==='Liabilitas') return 'badge-red';
  if(t==='Ekuitas') return 'badge-blue';
  if(t==='Pendapatan') return 'badge-blue';
  if(t==='HPP') return 'badge-yellow';
  return 'badge-yellow';
}

function renderAkun() {
  const body = document.getElementById('akun-body');
  const search = (document.getElementById('coa-search')?.value || '').toLowerCase();
  const filterTipe = document.getElementById('coa-filter-tipe')?.value || '';
  const filterKat = document.getElementById('coa-filter-kat')?.value || '';
  const grouped = document.getElementById('coa-group-tipe')?.checked !== false;
  const saldoMap = computeSaldoAll ? computeSaldoAll() : {};

  // Update category filter options
  const katSel = document.getElementById('coa-filter-kat');
  if(katSel && katSel.options.length <= 1) {
    const kats = [...new Set(akuns.map(a=>a.kat).filter(Boolean))].sort();
    kats.forEach(k => { const o=document.createElement('option'); o.value=k; o.textContent=k; katSel.appendChild(o); });
  }

  let filtered = akuns.filter(a => {
    if(filterTipe && a.tipe !== filterTipe) return false;
    if(filterKat && a.kat !== filterKat) return false;
    if(search && !a.nama.toLowerCase().includes(search) && !a.kode.includes(search)) return false;
    return true;
  });

  // Update count subtitle
  const subEl = document.getElementById('coa-count-sub');
  if(subEl) subEl.textContent = `${filtered.length} dari ${akuns.length} akun ditampilkan`;

  // Stats bar
  const statsEl = document.getElementById('coa-stats');
  if(statsEl) {
    const tipes = ['Aset','Liabilitas','Ekuitas','Pendapatan','HPP','Beban'];
    const colors = ['badge-green','badge-red','badge-blue','badge-blue','badge-yellow','badge-yellow'];
    statsEl.innerHTML = tipes.map((t,i) => {
      const n = akuns.filter(a=>a.tipe===t).length;
      return `<span class="badge ${colors[i]}" style="cursor:pointer;padding:4px 10px;font-size:11px;" 
        onclick="document.getElementById('coa-filter-tipe').value='${t}';renderAkun()">
        ${t} (${n})</span>`;
    }).join('') + `<span class="badge badge-gray" style="cursor:pointer;padding:4px 10px;font-size:11px;"
      onclick="document.getElementById('coa-filter-tipe').value='';renderAkun()">Semua (${akuns.length})</span>`;
  }

  if(!body) return;

  let html = '';
  if(grouped && !filterTipe && !search && !filterKat) {
    // Grouped by type
    const tipeOrder = ['Aset','Liabilitas','Ekuitas','Pendapatan','HPP','Beban'];
    const tipeLabels = {
      'Aset':'<i class="ti ti-building-bank" style="font-size:16px;width:16px;height:16px;vertical-align:-2px;margin-right:6px;"></i> ASET',
      'Liabilitas':'<i class="ti ti-clipboard-list ti-inline"></i> LIABILITAS',
      'Ekuitas':'💎 EKUITAS',
      'Pendapatan':'💰 PENDAPATAN',
      'HPP':'<i class="ti ti-package" style="font-size:14px;vertical-align:-2px;margin-right:4px;"></i> HARGA POKOK PENJUALAN',
      'Beban':'💸 BEBAN'
    };
    tipeOrder.forEach(tipe => {
      const group = filtered.filter(a => a.tipe === tipe);
      if(!group.length) return;
      // Group header
      html += `<tr style="background:var(--surface2);">
        <td colspan="7" style="padding:8px 16px;font-size:11px;font-weight:800;color:var(--muted);letter-spacing:0.08em;text-transform:uppercase;border-bottom:1px solid var(--border);">
          <span class="badge ${tipeBadge(tipe)}" style="margin-right:8px;">${tipe}</span>
          ${tipeLabels[tipe]} <span style="margin-left:8px;font-weight:400;">(${group.length} akun)</span>
        </td>
      </tr>`;
      // Sub-group by kategori
      const kats = [...new Set(group.map(a=>a.kat))];
      kats.forEach(kat => {
        const katGroup = group.filter(a=>a.kat===kat);
        if(kats.length > 1) {
          html += `<tr><td colspan="7" style="padding:5px 16px 3px 32px;font-size:10px;color:var(--muted);font-weight:600;letter-spacing:0.06em;text-transform:uppercase;background:rgba(255,255,255,0.02);">── ${kat}</td></tr>`;
        }
        katGroup.forEach(a => {
          html += buildAkunRow(a, saldoMap);
        });
      });
    });
  } else {
    filtered.forEach(a => { html += buildAkunRow(a, saldoMap); });
  }

  body.innerHTML = html || `<tr><td colspan="7" style="text-align:center;padding:24px;color:var(--muted);">Tidak ada akun ditemukan</td></tr>`;
}

function buildAkunRow(a, saldoMap) {
  const s = saldoMap[a.kode] || {debit:0, kredit:0};
  const saldo = a.normal==='D' ? s.debit-s.kredit : s.kredit-s.debit;
  const saldoColor = saldo > 0 ? 'var(--accent)' : saldo < 0 ? 'var(--red)' : 'var(--muted)';
  const isContra = a.kat === 'Kontra' || a.kat === 'Kontra HPP';
  return `<tr style="${isContra?'opacity:0.75;':''}">
    <td style="font-family:var(--mono);font-size:12px;color:var(--muted);">${a.kode}</td>
    <td style="font-size:13px;${isContra?'padding-left:28px;font-style:italic;':''}">
      ${isContra?'<span style="color:var(--muted);margin-right:4px;font-size:10px;">↳</span>':''}${a.nama}
    </td>
    <td><span class="badge ${tipeBadge(a.tipe)}" style="font-size:10px;">${a.tipe}</span></td>
    <td style="color:var(--muted);font-size:11.5px;">${a.kat || a.kategori || '—'}</td>
    <td><span class="badge ${a.normal==='D'?'badge-blue':'badge-red'}" style="font-size:10px;">${a.normal==='D'?'Debit':'Kredit'}</span></td>
    <td style="text-align:right;font-family:var(--mono);font-size:12px;color:${saldoColor};">${saldo?'Rp '+Math.abs(saldo).toLocaleString('id-ID'):'—'}</td>
    <td style="text-align:center;">
      <button onclick="hapusAkun('${a.kode}')" title="Hapus akun" style="background:none;border:none;color:var(--muted);cursor:pointer;font-size:13px;padding:2px 5px;border-radius:4px;opacity:0.5;" onmouseover="this.style.opacity='1';this.style.color='var(--red)'" onmouseout="this.style.opacity='0.5';this.style.color='var(--muted)'"><i class="ti ti-trash" style="font-size:14px;"></i></button>
    </td>
  </tr>`;
}

function hapusAkun(kode) {
  const a = akuns.find(x=>x.kode===kode);
  if(!a) return;
  // Check if used in journals
  const usedIn = jurnalEntries.filter(j=>j.lines.some(l=>l.akun===kode)).length;
  if(usedIn > 0) {
    showAlert(`❌ Akun "${a.nama}" tidak bisa dihapus — dipakai di ${usedIn} jurnal.`);
    return;
  }
  showCustomConfirmGeneral({
    icon: '<svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="color:var(--red)"><path d="M4 7h16M10 11v6M14 11v6M5 7l1 12a2 2 0 002 2h8a2 2 0 002-2l1-12M9 7V4h6v3"/></svg>',
    iconColor: 'rgba(248,113,113,0.15)',
    iconBorder: 'rgba(248,113,113,0.3)',
    title: 'Hapus Akun?',
    subtitle: `Akun <b>${a.kode} — ${a.nama}</b> akan dihapus permanen`,
    rows: [
      { label: 'Kode', value: a.kode, color: 'var(--muted)' },
      { label: 'Nama', value: a.nama, color: 'var(--text)' },
      { label: 'Tipe', value: a.tipe, color: 'var(--accent2)' },
    ],
    warning: '<i class="ti ti-alert-triangle" style="color:var(--accent3);font-size:13px;width:13px;height:13px;vertical-align:-2px;"></i> Aksi ini tidak bisa dibatalkan.',
    btnLabel: '[Hapus] Ya, Hapus Akun',
    btnGradient: 'linear-gradient(135deg,#f87171,#dc2626)',
  }).then(ok => {
    if(!ok) return;
    akuns = akuns.filter(x=>x.kode!==kode);
    renderAkun();
    markDirty();
    showAlert(`✓ Akun ${a.kode} - ${a.nama} dihapus`);
  });
}

function openModalAkun(){document.getElementById('modal-akun').classList.add('open');setTimeout(upgradeFormPickers,80);}
function closeModal(id){document.getElementById(id).classList.remove('open');}

// AKUN PICKER BOTTOM SHEET
let _pickerTriggerBtn = null;

function openAkunPicker(triggerBtn) {
  _simplePickerHiddenId = null; // reset simple picker state
  _simplePickerBtnId = null;
  _simplePickerFilter = null;
  _pickerTriggerBtn = triggerBtn;
  const row = triggerBtn.closest('.jurnal-line-row');
  const sel = row.querySelector('select');
  document.getElementById('akun-picker-search').value = '';
  renderAkunPickerList('', sel?.value || '');
  document.getElementById('akun-picker-backdrop').classList.add('open');
  setTimeout(()=>document.getElementById('akun-picker-search').focus(), 200);
}

function closeAkunPicker(e) {
  if(e && e.target !== document.getElementById('akun-picker-backdrop')) return;
  document.getElementById('akun-picker-backdrop').classList.remove('open');
  _pickerTriggerBtn = null;
  _simplePickerHiddenId = null;
  _simplePickerBtnId = null;
  _simplePickerFilter = null;
}

function filterAkunPicker(q) {
  if(_simplePickerHiddenId) {
    // Mode simple picker (form kas/pembelian)
    const currentVal = document.getElementById(_simplePickerHiddenId)?.value || '';
    renderFilteredPickerList(q, currentVal, _simplePickerFilter);
  } else if(_pickerTriggerBtn) {
    // Mode manual line picker
    const row = _pickerTriggerBtn?.closest('.jurnal-line-row');
    const sel = row?.querySelector('select');
    renderAkunPickerList(q, sel?.value || '');
  }
}

function renderAkunPickerList(query, selectedKode) {
  const q = query.toLowerCase();
  const filtered = akuns.filter(a =>
    !q || a.kode.includes(q) || a.nama.toLowerCase().includes(q) || a.tipe.toLowerCase().includes(q)
  );
  const list = document.getElementById('akun-picker-list');
  if(!filtered.length) {
    list.innerHTML = `<div id="akun-picker-empty"><i class="ti ti-mood-empty" style="font-size:20px;display:block;margin:0 auto 6px;"></i> Akun tidak ditemukan<br><small>Coba kata kunci lain</small></div>`;
    return;
  }
  // Group by tipe
  const groups = {};
  filtered.forEach(a => {
    if(!groups[a.tipe]) groups[a.tipe]=[];
    groups[a.tipe].push(a);
  });
  const tipeColor = t => ({Aset:'aset',Liabilitas:'liabilitas',Ekuitas:'ekuitas',Pendapatan:'pendapatan',Beban:'beban',HPP:'beban'})[t]||'beban';
  let html = '';
  Object.entries(groups).forEach(([tipe,items]) => {
    html += `<div class="akun-picker-group-label">${tipe}</div>`;
    items.forEach(a => {
      const sel = a.kode===selectedKode ? ' selected' : '';
      html += `<div class="akun-picker-item${sel}" onclick="_simplePickerHiddenId?selectSimplePicker('${a.kode}','${a.nama.replace(/'/g,"\\'")}'):selectAkunFromPicker('${a.kode}','${a.nama.replace(/'/g,"\\'")}')">
        <span class="akun-picker-kode">${a.kode}</span>
        <span class="akun-picker-nama">${a.nama}</span>
        <span class="akun-picker-tipe ${tipeColor(a.tipe)}">${tipe}</span>
      </div>`;
    });
  });
  list.innerHTML = html;
}

function selectAkunFromPicker(kode, nama) {
  if(!_pickerTriggerBtn) return;
  const row = _pickerTriggerBtn.closest('.jurnal-line-row');
  if(!row) return;
  const sel = row.querySelector('select');
  if(sel) sel.value = kode;
  _pickerTriggerBtn.textContent = kode + ' — ' + nama;
  document.getElementById('akun-picker-backdrop').classList.remove('open');
  _pickerTriggerBtn = null;
}

function syncAkunTrigger(sel) {
  const row = sel.closest('.jurnal-line-row');
  const btn = row?.querySelector('.akun-trigger-btn');
  if(!btn) return;
  const a = akuns.find(x=>x.kode===sel.value);
  if(a) btn.textContent = a.kode + ' — ' + a.nama;
}
function simpanAkun(){
  const kode=document.getElementById('new-akun-kode').value.trim();
  const nama=document.getElementById('new-akun-nama').value.trim();
  const tipe=document.getElementById('new-akun-tipe').value;
  const kat=document.getElementById('new-akun-kat').value.trim();
  if(!kode||!nama){showAlert('Kode dan nama akun wajib diisi!');return;}
  if(akuns.find(a=>a.kode===kode)){showAlert('Kode akun sudah ada!');return;}
  const normal=['Aset','Beban','HPP'].includes(tipe)?'D':'K';
  akuns.push({kode,nama,tipe,kat,normal});
  akuns.sort((a,b)=>a.kode.localeCompare(b.kode));
  closeModal('modal-akun');
  renderAkun();
  showAlert('✓ Akun berhasil ditambahkan!');
  ['new-akun-kode','new-akun-nama','new-akun-kat'].forEach(id=>document.getElementById(id).value='');
}

// EXPORT SYSTEM
let exportFmt = 'excel';
let excelTemplate = 'data'; // 'data' or 'formula'
let exportLogoDataUrl = null; // base64 logo for PDF

function openExportModal() {
  document.getElementById('exp-status').style.display = 'none';
  document.getElementById('exp-btn').disabled = false;
  document.getElementById('exp-btn').innerHTML = '<i class="ti ti-upload" style="font-size:16px;width:16px;height:16px;vertical-align:-2px;margin-right:6px;"></i> Export Sekarang';
  // Reset format ke excel setiap kali modal dibuka agar state konsisten
  exportFmt = 'excel';
  ['excel','pdf','csv'].forEach(f => {
    document.getElementById('exp-opt-'+f)?.classList.toggle('exp-fmt-active', f === 'excel');
  });
  // Pre-fill from profil
  const _p = typeof getProfil === 'function' ? getProfil() : {};
  const namaEl = document.getElementById('exp-nama-perusahaan');
  const periodeEl = document.getElementById('exp-periode');
  if(namaEl && !namaEl.value && _p.nama) namaEl.value = _p.nama;
  if(periodeEl && !periodeEl.value) periodeEl.value = new Date().toLocaleDateString('id-ID',{month:'long',year:'numeric'});
  document.getElementById('modal-export').classList.add('open');
  updateExportSections();
  _pvUpdateExportModalBadge();
}

function selectExportFmt(fmt) {
  exportFmt = fmt;
  ['excel','pdf','csv'].forEach(f => {
    document.getElementById('exp-opt-'+f).classList.toggle('exp-fmt-active', f === fmt);
  });
  updateExportSections();
}

function updateExportSections() {
  const isExcel = exportFmt === 'excel';
  const isPdf = exportFmt === 'pdf';
  document.getElementById('exp-excel-template-section').style.display = isExcel ? '' : 'none';
  document.getElementById('exp-pdf-logo-section').style.display = isPdf ? '' : 'none';
  const pvBtn = document.getElementById('exp-preview-btn');
  if(pvBtn) {
    pvBtn.disabled = !isPdf;
    pvBtn.style.cursor = isPdf ? 'pointer' : 'not-allowed';
    pvBtn.style.borderColor = isPdf ? 'var(--accent2)' : 'rgba(34,211,238,0.2)';
    pvBtn.style.color = isPdf ? 'var(--accent2)' : 'rgba(34,211,238,0.3)';
  }
}

function selectExcelTemplate(tmpl) {
  excelTemplate = tmpl;
  ['data','formula'].forEach(t => {
    document.getElementById('exp-tmpl-'+t).classList.toggle('exp-fmt-active', t === tmpl);
  });
  const desc = document.getElementById('exp-tmpl-desc');
  if(tmpl === 'data') {
    desc.innerHTML = '💡 <b style="color:var(--text)">Template Data:</b> Export data transaksi lengkap per sheet. Setiap sheet memiliki tabel terformat, total baris, dan sheet Referensi Formula sebagai panduan perhitungan manual di Excel/Spreadsheet.';
  } else {
    desc.innerHTML = '<i class="ti ti-settings ti-inline"></i> <b style="color:var(--accent2)">Template Hitung Otomatis:</b> Semua angka dihubungkan dengan formula Excel aktif. Sheet <b>INPUT</b> sebagai sumber data — ubah di sana, semua laporan (Laba Rugi, Neraca, Saldo) update otomatis. Ideal untuk input & analisis rutin.';
  }
}

function handleLogoUpload(input) {
  const file = input.files[0];
  if(!file) return;
  if(file.size > 2 * 1024 * 1024) { showAlert('❌ File logo terlalu besar (maks 2MB)'); return; }
  const reader = new FileReader();
  reader.onload = (e) => {
    exportLogoDataUrl = e.target.result;
    const img = document.getElementById('exp-logo-img');
    const placeholder = document.getElementById('exp-logo-placeholder');
    const removeBtn = document.getElementById('exp-logo-remove-btn');
    img.src = exportLogoDataUrl;
    img.style.display = 'block';
    placeholder.style.display = 'none';
    removeBtn.style.display = 'block';
    document.getElementById('exp-logo-preview-box').style.borderStyle = 'solid';
    document.getElementById('exp-logo-preview-box').style.borderColor = 'var(--accent)';
  };
  reader.readAsDataURL(file);
  input.value = '';
}

function removeLogo() {
  exportLogoDataUrl = null;
  const img = document.getElementById('exp-logo-img');
  const placeholder = document.getElementById('exp-logo-placeholder');
  const removeBtn = document.getElementById('exp-logo-remove-btn');
  img.src = '';
  img.style.display = 'none';
  placeholder.style.display = '';
  removeBtn.style.display = 'none';
  document.getElementById('exp-logo-preview-box').style.borderStyle = 'dashed';
  document.getElementById('exp-logo-preview-box').style.borderColor = 'var(--border)';
}

function expStatus(msg, color='var(--accent2)') {
  const el = document.getElementById('exp-status');
  el.style.display = 'block';
  el.style.color = color;
  el.innerHTML = msg;
}

function openPdfPreview() {
  window._pvExportInfo = {
    nama:    document.getElementById('exp-nama-perusahaan')?.value || '',
    proyek:  document.getElementById('exp-proyek')?.value || '',
    periode: document.getElementById('exp-periode')?.value || '',
    sections: {
      jurnal:    document.getElementById('exp-jurnal-umum')?.checked,
      labaRugi:  document.getElementById('exp-laba-rugi')?.checked,
      neraca:    document.getElementById('exp-neraca')?.checked,
      saldo:     document.getElementById('exp-neraca-saldo')?.checked,
      dashboard: document.getElementById('exp-dashboard')?.checked,
      pajak:     document.getElementById('exp-pajak')?.checked,
    }
  };
  closeModal('modal-export');
  const modal = document.getElementById('modal-pdf-preview');
  if(!modal) { showAlert('❌ Komponen preview belum dimuat. Coba refresh halaman.'); return; }
  modal.classList.add('open');
  _pvPanelOpen = false;
  document.getElementById('pv-panel')?.classList.add('hidden');
  // Sync tampilan kartu template dengan setting yang tersimpan
  ['A','B','C','D'].forEach(id => document.getElementById('pv-tc-'+id)?.classList.toggle('active', id === _pvTmpl));
  if(typeof pvRenderPalList === 'function') pvRenderPalList();
  if(typeof pvRenderRecent === 'function') pvRenderRecent();
  _pvPages = []; _pvCurPage = 0;
  if(typeof pvBuildPages === 'function') pvBuildPages();
}

// ── Helper: inject template aktif → exportPDF ──
function _pvInjectThemeAndExport(nama, periode, proyek) {
  function hexToRgb(hex){const h=(hex||'#000000').replace('#','');return[parseInt(h.slice(0,2),16)||0,parseInt(h.slice(2,4),16)||0,parseInt(h.slice(4,6),16)||0];}
  function lighten(rgb,p){return rgb.map(c=>Math.round(c+(255-c)*p));}

  // Selalu inject theme — pvGetC1/C2/C3 otomatis fallback ke default palette per template
  const c1hex = pvGetC1();
  const c2hex = pvGetC2();
  const c1 = hexToRgb(c1hex);
  const c2 = hexToRgb(c2hex);

  if(_pvTmpl === 'A') {
    // Corporate: header/footer pakai c1, accent pakai c2
    window._pvExportTheme = {DARK:c1, GREEN:c2, BLUE:c2, LIGHT:lighten(c1,0.93)};
  } else if(_pvTmpl === 'B') {
    // Klasik Minimal: garis & judul pakai c1, highlight/KPI pakai c2
    window._pvExportTheme = {DARK:c1, GREEN:c2, BLUE:c2, LIGHT:lighten(hexToRgb(pvGetC3()),0.02)};
  } else {
    // Modern Dark: sidebar pakai c1, aksen pakai c2, bg pakai c3
    const c3hex = pvGetC3();
    const c3 = hexToRgb(c3hex);
    const darkBg = c3.every(v=>v>180) ? [28,32,48] : c3;
    window._pvExportTheme = {DARK:darkBg, GREEN:c1, BLUE:c2, LIGHT:[226,232,240]};
  }

  exportPDF(nama, periode, proyek);
  window._pvExportTheme = null;
}

function doExport() {
  const btn = document.getElementById('exp-btn');
  btn.disabled = true;
  btn.innerHTML = '<svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="animation:spin 0.7s linear infinite;vertical-align:-2px"><path d="M12 2v4M12 18v4M4.93 4.93l2.83 2.83M16.24 16.24l2.83 2.83M2 12h4M18 12h4M4.93 19.07l2.83-2.83M16.24 7.76l2.83-2.83"/></svg> Memproses...';
  const p = typeof getProfil === 'function' ? getProfil() : {};
  const nama = document.getElementById('exp-nama-perusahaan').value || p.nama || 'PT Demo Indonesia';
  const proyek = document.getElementById('exp-proyek')?.value || '';
  const periode = document.getElementById('exp-periode').value || new Date().toLocaleDateString('id-ID',{month:'long',year:'numeric'});

  if(exportFmt === 'pdf') {
    // FIX: PDF export dari modal utama harus pakai sistem template HTML (pvExportNow),
    // bukan exportPDF lama (jsPDF). Inject export info, build pages dengan template aktif,
    // lalu panggil pvExportNow setelah pages selesai dirender.
    window._pvExportInfo = {
      nama, proyek, periode,
      sections: {
        jurnal:    document.getElementById('exp-jurnal-umum')?.checked,
        labaRugi:  document.getElementById('exp-laba-rugi')?.checked,
        neraca:    document.getElementById('exp-neraca')?.checked,
        saldo:     document.getElementById('exp-neraca-saldo')?.checked,
        dashboard: document.getElementById('exp-dashboard')?.checked,
        pajak:     document.getElementById('exp-pajak')?.checked,
      }
    };
    // Build pages menggunakan template & warna yang sedang aktif (_pvTmpl, _pvColors)
    const gen = document.getElementById('pv-generating');
    if(gen) gen.style.display = 'flex';
    setTimeout(() => {
      try {
        const sec = window._pvExportInfo.sections || {};
        const c1 = pvGetC1(), c2 = pvGetC2(), c3 = pvGetC3(), t = _pvTmpl;
        _pvPages = [];
        _pvPages.push(pvMakeCover(nama, periode, proyek, sec, t, c1, c2, c3));
        if(sec.dashboard) _pvPages.push(pvMakeDash(nama, periode, t, c1, c2, c3));
        if(sec.jurnal) _pvPages.push(...pvMakeJurnal(nama, periode, t, c1, c2, c3));
        if(sec.labaRugi) _pvPages.push(pvMakeLR(nama, periode, t, c1, c2, c3));
        if(sec.neraca) _pvPages.push(pvMakeNeraca(nama, periode, t, c1, c2, c3));
        if(sec.saldo) _pvPages.push(pvMakeSaldo(nama, periode, t, c1, c2, c3));
        if(sec.pajak) _pvPages.push(pvMakePajak(nama, periode, t, c1, c2, c3));
        if(!_pvPages.length) _pvPages.push(pvMakeCover(nama, periode, proyek, {}, t, c1, c2, c3));
        if(gen) gen.style.display = 'none';
        // Sekarang export dengan template yang sudah terisi
        pvExportNow();
        btn.disabled = false;
        btn.innerHTML = '<i class="ti ti-circle-check" style="color:var(--accent);font-size:13px;width:13px;height:13px;vertical-align:-2px;"></i> Selesai!';
        setTimeout(() => { btn.innerHTML = '<i class="ti ti-upload" style="font-size:16px;width:16px;height:16px;vertical-align:-2px;margin-right:6px;"></i> Export Sekarang'; btn.disabled = false; }, 2000);
      } catch(e) {
        if(gen) gen.style.display = 'none';
        expStatus('❌ Error: ' + e.message, 'var(--red)');
        btn.disabled = false;
        btn.innerHTML = '<i class="ti ti-upload" style="font-size:16px;width:16px;height:16px;vertical-align:-2px;margin-right:6px;"></i> Export Sekarang';
      }
    }, 100);
    return;
  }

  setTimeout(() => {
    try {
      if(exportFmt === 'excel') exportExcel(nama, periode, excelTemplate);
      else exportCSV(nama, periode);
      btn.disabled = false;
      btn.innerHTML = '<i class="ti ti-circle-check" style="color:var(--accent);font-size:13px;width:13px;height:13px;vertical-align:-2px;"></i> Selesai!';
      setTimeout(() => { btn.innerHTML = '<i class="ti ti-upload" style="font-size:16px;width:16px;height:16px;vertical-align:-2px;margin-right:6px;"></i> Export Sekarang'; btn.disabled = false; }, 2000);
    } catch(e) {
      expStatus('❌ Error: ' + e.message, 'var(--red)');
      btn.disabled = false;
      btn.innerHTML = '<i class="ti ti-upload" style="font-size:16px;width:16px;height:16px;vertical-align:-2px;margin-right:6px;"></i> Export Sekarang';
    }
  }, 100);
}

// ══════════════════════════════════════════════════════════════════════
// AUDIT TRAIL SYSTEM — dengan label role multi-user
// ══════════════════════════════════════════════════════════════════════

const AUDIT_KEY     = 'bhp_audit_trail';
const AUDIT_MAX     = 2000;
const AUDIT_PAGE_SZ = 40;
let   _auditPage       = 0;
let   _auditFilter     = 'all';
let   _auditRoleFilter = null; // null = semua role, string = filter spesifik role

const AUDIT_COLORS = {
  create:'#4ade80', delete:'#f87171', edit:'#fbbf24',
  auto:'#22d3ee',   login:'#a78bfa',  export:'#fb923c',
  reset:'#ef4444',  info:'#94a3b8',
};

const AUDIT_ROLE_BADGE = {
  owner:  { label:'<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:-1px"><path d=\"M2 20h20M5 20V10l7-6 7 6v10\"/><path d=\"M9 20v-5h6v5\"/></svg> Owner',  style:'background:rgba(250,204,21,0.15);color:#facc15;border:1px solid rgba(250,204,21,0.3);display:inline-flex;align-items:center;gap:4px;' },
  admin:  { label:'<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:-1px"><path d=\"M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z\"/></svg> Admin',  style:'background:rgba(34,211,238,0.12);color:var(--accent2);border:1px solid rgba(34,211,238,0.25);display:inline-flex;align-items:center;gap:4px;' },
  member: { label:'<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:-1px"><circle cx=\"12\" cy=\"8\" r=\"4\"/><path d=\"M4 20c0-4 3.6-7 8-7s8 3 8 7\"/></svg> Member', style:'background:rgba(148,163,184,0.12);color:#94a3b8;border:1px solid rgba(148,163,184,0.2);display:inline-flex;align-items:center;gap:4px;' },
  guest:  { label:'<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:-1px"><rect x=\"3\" y=\"11\" width=\"18\" height=\"11\" rx=\"2\"/><path d=\"M7 11V7a5 5 0 0 1 9.9-1\"/></svg> Guest',  style:'background:rgba(148,163,184,0.08);color:#64748b;border:1px solid rgba(148,163,184,0.15);display:inline-flex;align-items:center;gap:4px;' },
  system: { label:'<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:-1px"><circle cx=\"12\" cy=\"12\" r=\"3\"/><path d=\"M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1-2.83 2.83l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-4 0v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83-2.83l.06-.06A1.65 1.65 0 0 0 4.68 15a1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1 0-4h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 2.83-2.83l.06.06A1.65 1.65 0 0 0 9 4.68a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 4 0v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 2.83l-.06.06A1.65 1.65 0 0 0 19.4 9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 0 4h-.09a1.65 1.65 0 0 0-1.51 1z\"/></svg> Sistem', style:'background:rgba(139,92,246,0.12);color:#a78bfa;border:1px solid rgba(139,92,246,0.25);display:inline-flex;align-items:center;gap:4px;' },
};

// ── Determine current actor role ──────────────────────────────────────────
function _getActorRole() {
  // Guest / local mode
  if (typeof isGuestMode !== 'undefined' && isGuestMode) return 'guest';
  if (typeof currentUser === 'undefined' || !currentUser)  return 'guest';
  // Owner: company creator
  if (typeof currentCompany !== 'undefined' && currentCompany
      && currentCompany.user_id === currentUser.id) return 'owner';
  // Admin
  if (typeof _currentMemberRole !== 'undefined' && _currentMemberRole === 'admin') return 'admin';
  // Member
  if (typeof _currentMemberRole !== 'undefined' && _currentMemberRole === 'member') return 'member';
  // Fallback: if there's a logged-in user but no company context yet
  if (currentUser?.id) return 'admin'; // treat as admin for solo use
  return 'guest';
}

function _getCurrentActorLabel() {
  if (typeof currentUser !== 'undefined' && currentUser?.email) {
    return currentUser.user_metadata?.full_name
        || currentUser.user_metadata?.name
        || currentUser.email;
  }
  if (typeof isGuestMode !== 'undefined' && isGuestMode) return 'Guest (Lokal)';
  return 'Pengguna';
}

// ── Core logger ───────────────────────────────────────────────────────────
function auditLog(action, category, description, meta = {}) {
  try {
    const logs  = auditGetAll();
    const who   = _getCurrentActorLabel();
    const role  = _getActorRole();
    const entry = {
      id:   'AL_' + Date.now() + '_' + Math.random().toString(36).slice(2,6),
      ts:   new Date().toISOString(),
      action, category, description, who, role,
      meta,
    };
    logs.unshift(entry);
    if (logs.length > AUDIT_MAX) logs.length = AUDIT_MAX;
    localStorage.setItem(AUDIT_KEY, JSON.stringify(logs));
  } catch(e) { console.warn('[Audit] Failed:', e); }
}

function auditGetAll() {
  try { return JSON.parse(localStorage.getItem(AUDIT_KEY)||'[]'); } catch { return []; }
}

// ── Render ────────────────────────────────────────────────────────────────
function renderAuditTrail() {
  const logs   = auditGetAll();
  const search = (document.getElementById('audit-search')?.value||'').toLowerCase();
  const filtered = logs.filter(e => {
    if (_auditFilter !== 'all' && e.action !== _auditFilter) return false;
    if (_auditRoleFilter !== null && (e.role||'guest') !== _auditRoleFilter) return false;
    if (search && !e.description.toLowerCase().includes(search)
               && !e.category.toLowerCase().includes(search)
               && !(e.who||'').toLowerCase().includes(search)
               && !(e.meta?.ref||'').toLowerCase().includes(search)) return false;
    return true;
  });
  _renderAuditKPI(logs);
  const el = document.getElementById('audit-trail-list');
  if (!el) return;
  const slice = filtered.slice(0, (_auditPage+1)*AUDIT_PAGE_SZ);
  if (!slice.length) {
    el.innerHTML = `<div class="at-trail-empty">
      <i class="ti ti-shield-off"></i>
      ${logs.length ? 'Tidak ada aktivitas sesuai filter.' : 'Belum ada aktivitas tercatat.<br><span style="font-size:12px;">Log muncul saat kamu mulai menggunakan aplikasi.</span>'}
    </div>`;
    document.getElementById('audit-load-more').style.display='none';
    return;
  }
  el.innerHTML = slice.map((e,i) => {
    const isLast  = i === slice.length-1;
    const color   = AUDIT_COLORS[e.action] || AUDIT_COLORS.info;
    const timeStr = _auditFmtTime(e.ts);
    const rb      = AUDIT_ROLE_BADGE[e.role||'guest'] || AUDIT_ROLE_BADGE.guest;
    const diffHtml = e.meta?.diff ? _renderDiff(e.meta.diff) : '';
    const metaHtml = e.meta?.ref ? `<div class="at-trail-meta">${e.meta.ref}</div>` : '';
    return `<div class="at-trail-row">
      <div class="at-trail-timeline">
        <div class="at-trail-dot" style="background:${color};"></div>
        ${!isLast?'<div class="at-trail-line"></div>':''}
      </div>
      <div class="at-trail-card">
        <div class="at-trail-header">
          <span class="at-trail-action ${e.action}">${_auditActionLabel(e.action)}</span>
          <span class="at-trail-role-badge" style="${rb.style};font-size:10px;font-weight:700;padding:1px 7px;border-radius:5px;flex-shrink:0;">${rb.label}</span>
          <span class="at-trail-who"><i class="ti ti-user" style="font-size:10px;vertical-align:-1px;margin-right:3px;"></i>${e.who||'—'}</span>
          <span class="at-trail-time">${timeStr}</span>
        </div>
        <div class="at-trail-desc">${e.description}</div>
        ${metaHtml}${diffHtml}
      </div>
    </div>`;
  }).join('');
  const lm = document.getElementById('audit-load-more');
  if (lm) lm.style.display = filtered.length > slice.length ? '' : 'none';
}

function _renderAuditKPI(logs) {
  const el = document.getElementById('audit-kpi'); if (!el) return;
  const today = new Date().toISOString().slice(0,10);
  const todayLogs = logs.filter(e=>e.ts.startsWith(today));
  // Count by role
  const ownerCount  = logs.filter(e=>e.role==='owner').length;
  const memberCount = logs.filter(e=>e.role==='member'||e.role==='admin').length;
  const kpis = [
    { label:'Total Log',        val:logs.length.toLocaleString('id-ID'), icon:'shield-check',   clr:'var(--accent2)' },
    { label:'Hari Ini',         val:todayLogs.length,                    icon:'calendar-today', clr:'var(--accent)'  },
    { label:'Aksi Hapus',       val:logs.filter(e=>e.action==='delete').length, icon:'trash',   clr:'var(--red)'     },
    { label:'Oleh Owner',       val:ownerCount,                           icon:'crown',          clr:'#facc15'        },
    { label:'Oleh Tim',         val:memberCount,                          icon:'users',          clr:'var(--accent3)' },
  ];
  el.innerHTML = kpis.map(k=>
    `<div style="flex:1;min-width:110px;background:var(--surface);border:0.5px solid var(--border);border-radius:12px;padding:12px 14px;">
      <div style="font-size:11px;color:var(--muted);display:flex;align-items:center;gap:5px;"><i class="ti ti-${k.icon}" style="font-size:12px;"></i>${k.label}</div>
      <div style="font-size:16px;font-weight:700;color:${k.clr};margin-top:4px;">${k.val}</div>
    </div>`
  ).join('');
}

function _auditActionLabel(action) {
  return {create:'<svg xmlns="http://www.w3.org/2000/svg" width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" style="vertical-align:-1px"><line x1=\"12\" y1=\"5\" x2=\"12\" y2=\"19\"/><line x1=\"5\" y1=\"12\" x2=\"19\" y2=\"12\"/></svg> Buat',delete:'<svg xmlns="http://www.w3.org/2000/svg" width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:-1px"><polyline points=\"3 6 5 6 21 6\"/><path d=\"M19 6l-1 14H6L5 6\"/><path d=\"M10 11v6M14 11v6\"/><path d=\"M9 6V4h6v2\"/></svg> Hapus',edit:'<svg xmlns="http://www.w3.org/2000/svg" width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:-1px"><path d=\"M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7\"/><path d=\"M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z\"/></svg> Edit',
          auto:'<svg xmlns="http://www.w3.org/2000/svg" width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:-1px"><polygon points=\"13 2 3 14 12 14 11 22 21 10 12 10 13 2\"/></svg> Otomatis',login:'<svg xmlns="http://www.w3.org/2000/svg" width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:-1px"><rect x=\"3\" y=\"11\" width=\"18\" height=\"11\" rx=\"2\"/><path d=\"M7 11V7a5 5 0 0 1 10 0v4\"/></svg> Sesi',export:'<svg xmlns="http://www.w3.org/2000/svg" width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:-1px"><path d=\"M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4\"/><polyline points=\"17 8 12 3 7 8\"/><line x1=\"12\" y1=\"3\" x2=\"12\" y2=\"15\"/></svg> Export',
          reset:'<svg xmlns="http://www.w3.org/2000/svg" width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:-1px"><path d=\"M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z\"/><line x1=\"12\" y1=\"9\" x2=\"12\" y2=\"13\"/><line x1=\"12\" y1=\"17\" x2=\"12.01\" y2=\"17\"/></svg> Reset',info:'<svg xmlns="http://www.w3.org/2000/svg" width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:-1px"><circle cx=\"12\" cy=\"12\" r=\"10\"/><line x1=\"12\" y1=\"8\" x2=\"12\" y2=\"12\"/><line x1=\"12\" y1=\"16\" x2=\"12.01\" y2=\"16\"/></svg> Info'}[action]||action;
}

function _auditFmtTime(iso) {
  try {
    const d=new Date(iso),now=new Date(),diff=now-d,min=Math.floor(diff/60000);
    if(min<1) return 'Baru saja';
    if(min<60) return `${min} mnt lalu`;
    const h=Math.floor(min/60);
    if(h<24) return `${h} jam lalu`;
    const dy=Math.floor(h/24);
    if(dy<7) return `${dy} hari lalu`;
    return d.toLocaleDateString('id-ID',{day:'numeric',month:'short',year:'numeric'})
      +' '+d.toLocaleTimeString('id-ID',{hour:'2-digit',minute:'2-digit'});
  } catch { return iso; }
}

function _renderDiff(diff) {
  if(!diff) return '';
  const rows = Object.entries(diff).map(([f,{old:o,new:n}])=>
    `<div><span style="color:var(--muted);min-width:80px;display:inline-block;">${f}:</span>`+
    `<span class="at-trail-diff-old">${o??'—'}</span> → <span class="at-trail-diff-new">${n??'—'}</span></div>`
  ).join('');
  return `<div class="at-trail-diff">${rows}</div>`;
}

// ── Role filter toggle (label role badges) ────────────────────────────────
function auditToggleRoleFilter(role) {
  // Klik badge yang sama dua kali = reset ke semua
  if (_auditRoleFilter === role) {
    _auditRoleFilter = null;
  } else {
    _auditRoleFilter = role;
  }
  _auditPage = 0;
  // Update visual state semua badge
  document.querySelectorAll('.at-role-filter-badge').forEach(b => {
    b.style.opacity = '1';
    b.style.boxShadow = '';
    b.style.transform = '';
  });
  if (_auditRoleFilter !== null) {
    // Redup badge yang tidak aktif, highlight yang aktif
    document.querySelectorAll('.at-role-filter-badge').forEach(b => {
      if (b.id !== 'audit-role-' + _auditRoleFilter) {
        b.style.opacity = '0.35';
      } else {
        b.style.boxShadow = '0 0 0 2px currentColor';
        b.style.transform = 'scale(1.08)';
      }
    });
  }
  renderAuditTrail();
}

// ── Filter & pagination ───────────────────────────────────────────────────
function auditSetFilter(f) {
  _auditFilter=f; _auditPage=0;
  document.querySelectorAll('.at-trail-filter-btn').forEach(b=>b.classList.remove('active'));
  document.getElementById('audit-f-'+f)?.classList.add('active');
  renderAuditTrail();
}
function auditLoadMore() { _auditPage++; renderAuditTrail(); }

// ── Export CSV ────────────────────────────────────────────────────────────
function auditExportCSV() {
  const logs=auditGetAll();
  if(!logs.length){showAlert('Belum ada log audit.');return;}
  const header=['Waktu','Aksi','Kategori','Deskripsi','Oleh','Role','Referensi'];
  const rows=logs.map(e=>[
    new Date(e.ts).toLocaleString('id-ID'),
    e.action,e.category,e.description,e.who||'',e.role||'',e.meta?.ref||''
  ].map(v=>`"${String(v).replace(/"/g,'""')}"`));
  const csv=[header,...rows].map(r=>r.join(',')).join('\n');
  const blob=new Blob(['﻿'+csv],{type:'text/csv;charset=utf-8;'});
  const url=URL.createObjectURL(blob);
  const a=document.createElement('a');
  a.href=url;a.download=`audit-trail-${new Date().toISOString().slice(0,10)}.csv`;
  a.click();URL.revokeObjectURL(url);
  auditLog('export','system',`Export audit trail CSV — ${logs.length} entri`);
}

// ── Clear old >90 days ────────────────────────────────────────────────────
function auditClearOld() {
  const cutoff=new Date(Date.now()-90*24*3600*1000).toISOString();
  const logs=auditGetAll(),before=logs.length;
  const fresh=logs.filter(e=>e.ts>=cutoff);
  localStorage.setItem(AUDIT_KEY,JSON.stringify(fresh));
  const removed=before-fresh.length;
  auditLog('info','system',`Membersihkan ${removed} log audit lama (>90 hari)`);
  renderAuditTrail();
  showAlert(`${removed} log lama dihapus.`);
}

// ── Init page ─────────────────────────────────────────────────────────────
function initAuditPage() {
  _auditPage=0;_auditFilter='all';_auditRoleFilter=null;
  document.querySelectorAll('.at-trail-filter-btn').forEach(b=>b.classList.remove('active'));
  document.getElementById('audit-f-all')?.classList.add('active');
  document.querySelectorAll('.at-role-filter-badge').forEach(b=>{b.style.opacity='1';b.style.boxShadow='';b.style.transform='';});
  const s=document.getElementById('audit-search');if(s)s.value='';
  renderAuditTrail();
}

