// MASTER KONTAK
// ══════════════════════════════════════════════════════════════
let _kontakFilter='semua';
function filterKontak(tipe){_kontakFilter=tipe;document.querySelectorAll('.kontak-tab').forEach(b=>b.classList.remove('oas-active-tab'));document.getElementById('kontak-tab-'+tipe)?.classList.add('oas-active-tab');renderKontak();}
function openModalKontak(editId=null){
  try {
    const f=editId?kontakList.find(k=>k.id===editId):null;
    const setVal=(id,v)=>{const el=document.getElementById(id);if(el){el.value=v||'';if(el.tagName==='SELECT')el.dispatchEvent(new Event('change',{bubbles:true}));}};
    ['kontak-edit-id','kontak-nama','kontak-telp','kontak-email','kontak-alamat','kontak-npwp','kontak-pic','kontak-catatan'].forEach(id=>setVal(id,''));
    setVal('kontak-edit-id', editId||'');
    if(f){setVal('kontak-nama',f.nama);setVal('kontak-telp',f.telp);setVal('kontak-email',f.email);setVal('kontak-alamat',f.alamat);setVal('kontak-npwp',f.npwp);setVal('kontak-pic',f.pic);setVal('kontak-catatan',f.catatan);const tp=document.getElementById('kontak-tipe');if(tp){tp.value=f.tipe||'pelanggan';tp.dispatchEvent(new Event('change',{bubbles:true}));}}
    openModal('modal-kontak');
    setTimeout(upgradeFormPickers,80);
  } catch(e){ console.error('openModalKontak:',e); }
}
function simpanKontak(){const nama=document.getElementById('kontak-nama').value.trim();if(!nama){showAlert('Nama kontak wajib diisi.');return;}const editId=document.getElementById('kontak-edit-id').value;const kontak={id:editId||'KTK_'+Date.now(),nama,tipe:document.getElementById('kontak-tipe').value,telp:document.getElementById('kontak-telp').value.trim(),email:document.getElementById('kontak-email').value.trim(),alamat:document.getElementById('kontak-alamat').value.trim(),npwp:document.getElementById('kontak-npwp').value.trim(),pic:document.getElementById('kontak-pic').value.trim(),catatan:document.getElementById('kontak-catatan').value.trim(),createdAt:editId?(kontakList.find(k=>k.id===editId)?.createdAt||new Date().toISOString()):new Date().toISOString()};if(editId){const idx=kontakList.findIndex(k=>k.id===editId);if(idx>=0)kontakList[idx]=kontak;}else kontakList.unshift(kontak);saveFiturBaru();closeModal('modal-kontak');renderKontak();renderKontakKPI();showAlert(`Kontak "${nama}" berhasil disimpan!`);}
function hapusKontak(id){if(!confirm('Hapus kontak ini?'))return;kontakList=kontakList.filter(k=>k.id!==id);saveFiturBaru();renderKontak();renderKontakKPI();showAlert('Kontak dihapus.');}
function lihatDetailKontak(id){const k=kontakList.find(c=>c.id===id);if(!k)return;const totalInvoice=invoiceList.filter(i=>i.pelanggan===k.nama).reduce((s,i)=>s+i.total,0);const totalTrxJurnal=jurnalEntries.filter(j=>j.kontakId===id).reduce((s,j)=>{const t=(j.lines||[]).filter(l=>l.debit>0).reduce((a,l)=>a+l.debit,0);return s+t;},0);const totalKeseluruhan=totalInvoice+(k.totalTrx||0);const tipeLabel={pelanggan:'Pelanggan',supplier:'Supplier',keduanya:'Keduanya'}[k.tipe]||k.tipe;document.getElementById('kontak-detail-title').textContent=k.nama;document.getElementById('kontak-detail-body').innerHTML=`<div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:16px;"><div><div style="font-size:10px;color:var(--muted);text-transform:uppercase;letter-spacing:.08em;margin-bottom:4px;">Tipe</div><div>${tipeLabel}</div></div><div><div style="font-size:10px;color:var(--muted);text-transform:uppercase;letter-spacing:.08em;margin-bottom:4px;">Telepon</div><div>${k.telp||'—'}</div></div><div><div style="font-size:10px;color:var(--muted);text-transform:uppercase;letter-spacing:.08em;margin-bottom:4px;">Email</div><div>${k.email||'—'}</div></div><div><div style="font-size:10px;color:var(--muted);text-transform:uppercase;letter-spacing:.08em;margin-bottom:4px;">NPWP</div><div style="font-family:var(--mono);font-size:12px;">${k.npwp||'—'}</div></div>${k.alamat?`<div style="grid-column:1/-1;"><div style="font-size:10px;color:var(--muted);text-transform:uppercase;letter-spacing:.08em;margin-bottom:4px;">Alamat</div><div>${k.alamat}</div></div>`:''}</div><div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:12px;">${totalInvoice?`<div style="background:var(--surface2);border-radius:10px;padding:12px 14px;"><div style="font-size:11px;color:var(--muted);margin-bottom:4px;">Total Invoice</div><div style="font-size:15px;font-weight:600;color:var(--accent);">${rp(totalInvoice)}</div></div>`:''}<div style="background:var(--surface2);border-radius:10px;padding:12px 14px;"><div style="font-size:11px;color:var(--muted);margin-bottom:4px;">Total Transaksi</div><div style="font-size:15px;font-weight:600;color:var(--accent2);">${rp((k.totalTrx||0))}</div></div>${(k.totalPenjualan||0)>0?`<div style="background:var(--surface2);border-radius:10px;padding:10px 12px;"><div style="font-size:10px;color:var(--muted);margin-bottom:2px;">Penjualan</div><div style="font-size:13px;font-weight:600;color:var(--accent);">${rp(k.totalPenjualan)}</div></div>`:''} ${(k.totalPembelian||0)>0?`<div style="background:var(--surface2);border-radius:10px;padding:10px 12px;"><div style="font-size:10px;color:var(--muted);margin-bottom:2px;">Pembelian</div><div style="font-size:13px;font-weight:600;color:var(--accent3);">${rp(k.totalPembelian)}</div></div>`:''}</div><div style="display:flex;gap:8px;margin-top:4px;"><button class="btn btn-ghost btn-sm" onclick="closeModal('modal-kontak-detail');openModalKontak('${id}')"><i class="ti ti-pencil ti-btn"></i> Edit</button><button class="btn btn-danger btn-sm" onclick="closeModal('modal-kontak-detail');hapusKontak('${id}')"><i class="ti ti-trash ti-btn"></i> Hapus</button></div>`;openModal('modal-kontak-detail');}
function renderKontakKPI(){const el=document.getElementById('kontak-kpi');if(!el)return;const pelanggan=kontakList.filter(k=>k.tipe==='pelanggan'||k.tipe==='keduanya').length;const supplier=kontakList.filter(k=>k.tipe==='supplier'||k.tipe==='keduanya').length;const kpis=[{label:'Total Kontak',val:kontakList.length+' kontak',icon:'users',clr:'var(--accent2)'},{label:'Pelanggan',val:pelanggan+' kontak',icon:'user-check',clr:'var(--accent)'},{label:'Supplier',val:supplier+' kontak',icon:'building-warehouse',clr:'var(--accent3)'}];el.innerHTML=kpis.map(k=>`<div style="flex:1;min-width:120px;background:var(--surface);border:0.5px solid var(--border);border-radius:12px;padding:12px 14px;"><div style="font-size:11px;color:var(--muted);display:flex;align-items:center;gap:5px;"><i class="ti ti-${k.icon}"></i> ${k.label}</div><div style="font-size:15px;font-weight:600;color:${k.clr};margin-top:4px;">${k.val}</div></div>`).join('');}
function renderKontak(){const tbody=document.getElementById('kontak-tbody');if(!tbody)return;const search=(document.getElementById('kontak-search')?.value||'').toLowerCase();const list=kontakList.filter(k=>{const matchTipe=_kontakFilter==='semua'||k.tipe===_kontakFilter||k.tipe==='keduanya';const matchSearch=!search||k.nama.toLowerCase().includes(search)||k.telp?.includes(search)||k.email?.toLowerCase().includes(search);return matchTipe&&matchSearch;});if(!list.length){tbody.innerHTML=`<tr><td colspan="7" style="text-align:center;color:var(--muted);padding:32px;">Belum ada kontak</td></tr>`;return;}const tipeMap={pelanggan:`<span style="background:var(--accent)22;color:var(--accent);padding:2px 8px;border-radius:6px;font-size:11px;">Pelanggan</span>`,supplier:`<span style="background:var(--accent3)22;color:var(--accent3);padding:2px 8px;border-radius:6px;font-size:11px;">Supplier</span>`,keduanya:`<span style="background:var(--accent2)22;color:var(--accent2);padding:2px 8px;border-radius:6px;font-size:11px;">Keduanya</span>`};tbody.innerHTML=list.map(k=>{const totalInvoice=invoiceList.filter(i=>i.pelanggan===k.nama).reduce((s,i)=>s+i.total,0);const totalDirect=k.totalTrx||0;const totalAll=totalInvoice+totalDirect;return `<tr><td style="font-weight:500;cursor:pointer;" onclick="lihatDetailKontak('${k.id}')">${k.nama}</td><td>${tipeMap[k.tipe]||k.tipe}</td><td style="font-size:12px;color:var(--muted)">${k.telp||'—'}</td><td style="font-size:12px;color:var(--muted)">${k.email||'—'}</td><td style="font-size:12px;color:var(--muted);max-width:160px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${k.alamat||'—'}</td><td style="text-align:right;font-family:var(--mono);color:${totalAll?'var(--accent)':'var(--muted)'};">${totalAll?rp(totalAll):'—'}</td><td style="display:flex;gap:4px;"><button class="btn btn-ghost btn-sm" onclick="lihatDetailKontak('${k.id}')" title="Lihat"><i class="ti ti-eye"></i></button><button class="btn btn-ghost btn-sm" onclick="openModalKontak('${k.id}')" title="Edit"><i class="ti ti-pencil"></i></button><button class="btn btn-danger btn-sm" onclick="hapusKontak('${k.id}')" title="Hapus"><i class="ti ti-trash"></i></button></td></tr>`;}).join('');}


