    okBtn.classList.remove('loading');
    okBtn.disabled = false;
    okBtn.innerHTML = '<i class="ti ti-trash ti-btn"></i> Hapus Permanen';
    showAlert('❌ Gagal menghapus bisnis: ' + (e.message || e));
